class Solution:
    def largestPrime(self, n: int) -> int:
        def is_prime(x):
            if x < 2:
                return False
            if x < 4:
                return True
            if x % 2 == 0:
                return False
            d = 3
            while d * d <= x:
                if x % d == 0:
                    return False
                d += 2
            return True
        best = 0
        total = 0
        p = 2
        while p <= n:
            if is_prime(p):
                total += p
                if total > n:
                    break
                if is_prime(total):
                    best = total
            p += 1
        return best

