class Solution:
    def largestPrime(self, n: int) -> int:
        size = n + 1
        sieve = bytearray([1]) * size
        if size > 0:
            sieve[0] = 0
        if size > 1:
            sieve[1] = 0
        i = 2
        while i * i <= n:
            if sieve[i]:
                for j in range(i * i, n + 1, i):
                    sieve[j] = 0
            i += 1
        best = 0
        total = 0
        for p in range(2, n + 1):
            if not sieve[p]:
                continue
            total += p
            if total > n:
                break
            if sieve[total]:
                best = total
        return best

