var largestPrime = function(n) {
    const size = n + 1;
    const sieve = new Uint8Array(size).fill(1);
    if (size > 0) sieve[0] = 0;
    if (size > 1) sieve[1] = 0;
    for (let i = 2; i * i <= n; i++) {
        if (sieve[i]) {
            for (let j = i * i; j <= n; j += i) sieve[j] = 0;
        }
    }
    let best = 0;
    let total = 0;
    for (let p = 2; p <= n; p++) {
        if (!sieve[p]) continue;
        total += p;
        if (total > n) break;
        if (sieve[total]) best = total;
    }
    return best;
};
